// Flowise Custom Tool Function
const validateInvoiceTotals = (extraction: Invoice): boolean => {
  const lineItemTotal = extraction.line_items.reduce(
    (sum, item) => sum + (item.quantity * item.unit_price),
    0
  );
  const diff = Math.abs(lineItemTotal - extraction.total_amount);
  return diff <= 0.01; // Allow small floating point differences
};

