import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  apiKey: process.env.VEX_API_KEY!,
  projectId: 'flowise-extraction',
  riskProfile: 'medium'
});

// Add to Flowise server startup
app.use('/api/v1/prediction/:id', vex.middleware());

import { defineCheck } from '@vex_dev/sdk/checks';

const schemaCompliance = defineCheck({
  name: 'invoice_schema_compliance',
  description: 'Verify extracted data matches invoice schema',
  verify: async ({ input, output }) => {
    const result = InvoiceSchema.safeParse(output);
    if (!result.success) {
      return {
        passed: false,
        reason: 'Schema violation',
        issues: result.error.issues
      };
    }
    return { passed: true };
  }
});

vex.addCheck(schemaCompliance);

// Complete Flowise callback handler
const vexVerifyExtraction = async (input: any, output: any) => {
  const checks = await vex.run([
    schemaCompliance,
    {
      name: 'retrieval_relevance',
      verify: ({ context }) => {
        const relevance = await computeSemanticSimilarity(input.query, context);
        return relevance > 0.75;
      }
    },
    {
      name: 'extraction_completeness',
      verify: ({ output }) => {
        return output.line_items?.length > 0 && output.total_amount > 0;
      }
    }
  ], { input, output });

  if (!checks.allPassed()) {
    throw new Error(`Extraction failed checks: ${checks.failedReasons()}`);
  }
  return output;
};
